import { Loader2 } from "lucide-react";

export function LoadingPage() {
  return (
    <div className="flex items-center justify-center py-24">
      <div className="text-center">
        <Loader2 className="mx-auto size-10 animate-spin text-muted-foreground" />
        <span className="sr-only">Loading...</span>
      </div>
    </div>
  );
}

import { useNavigate } from "@tanstack/react-router";
import { AlertTriangle, ArrowLeft, RotateCw, Send } from "lucide-react";
import posthog from "posthog-js";

import { Button } from "@/components/ui/button";

interface ErrorPageProps {
  error: Error;
  reset: () => void;
}

export function ErrorPage({ error, reset }: ErrorPageProps) {
  const navigate = useNavigate();

  function handleFeedback() {
    posthog.capture("feedback_submitted", {
      error: error.message,
      source: "error_page",
      url: typeof window !== "undefined" ? window.location.href : "",
    });

import { useNavigate } from "@tanstack/react-router";
import { ArrowLeft, FileQuestion } from "lucide-react";

import { Button } from "@/components/ui/button";

export function NotFoundPage() {
  const navigate = useNavigate();

  return (
    <div className="flex items-center justify-center py-24">
      <div className="text-center">
        <FileQuestion className="mx-auto size-16 text-muted-foreground" />
        <h1 className="mt-6 font-bold text-6xl text-foreground">404</h1>
        <p className="mt-4 text-gray-700 text-xl">Page not found</p>
        <p className="mt-2 text-gray-400 text-sm">
          The page you're looking for doesn't exist or has been moved.
        </p>
        <Button
          className="mt-8"
          onClick={() => navigate({ to: "/" })}

import { TanStackDevtools } from "@tanstack/react-devtools";
import { createRootRoute, HeadContent, Scripts } from "@tanstack/react-router";
import { TanStackRouterDevtoolsPanel } from "@tanstack/react-router-devtools";

import PostHogProvider from "#/posthog/provider";
import { Devtools } from "@/components/devtools";
import { TooltipProvider } from "@/components/ui/tooltip";

import css from "./styles.css?url";

export const Route = createRootRoute({
  head: () => ({
    links: [{ href: css, rel: "stylesheet" }],
    meta: [
      { charSet: "utf-8" },
      { content: "width=device-width, initial-scale=1", name: "viewport" },
      { title: "Alpauls Recruitment" },
    ],
  }),
  shellComponent: RootDocument,

